using Asp.Versioning;using Fixar.API.Security;using Fixar.Application.Common.Interfaces;using Fixar.Application.Common.Models;using Fixar.Domain.Entities;using Fixar.Infrastructure.Identity;using Fixar.Infrastructure.Persistence;using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;
namespace Fixar.API.Controllers;

[ApiController,ApiVersion("1.0"),Route("api/v{version:apiVersion}/maintenance-work-orders"),Authorize(Policy=AuthorizationPolicies.CanViewMaintenance)]
public class MaintenanceWorkOrdersController(ApplicationDbContext db,ICurrentUserService user):ControllerBase
{
 [HttpGet]public async Task<IActionResult>List(string? status,Guid? assetId,CancellationToken ct){var q=db.MaintenanceWorkOrders.AsNoTracking().AsQueryable();if(status!=null)q=q.Where(x=>x.Status==status);if(assetId.HasValue)q=q.Where(x=>x.MaintenanceAssetId==assetId);return Ok(ApiResponse<object>.SuccessResponse(await q.OrderByDescending(x=>x.PlannedStart).Select(x=>new{x.Id,x.MaintenanceWorkOrderNumber,x.MaintenanceAssetId,Asset=x.MaintenanceAsset.AssetName,x.MaintenanceRequestId,x.PreventiveMaintenancePlanId,x.WorkType,x.Priority,x.Title,x.Status,x.PlannedStart,x.PlannedEnd,x.ActualStart,x.ActualEnd,x.AssignedToName,x.DowntimeMinutes,x.LaborMinutes,x.TotalPartsCost,x.TotalMaintenanceCost,x.Currency}).ToListAsync(ct)));}
 [HttpGet("{id:guid}")]public async Task<IActionResult>Get(Guid id,CancellationToken ct){var x=await db.MaintenanceWorkOrders.AsNoTracking().Where(x=>x.Id==id).Select(x=>new{x.Id,x.MaintenanceWorkOrderNumber,x.MaintenanceAssetId,Asset=x.MaintenanceAsset.AssetName,x.MaintenanceRequestId,x.PreventiveMaintenancePlanId,x.WorkType,x.Priority,x.Title,x.Description,x.Status,x.PlannedStart,x.PlannedEnd,x.ActualStart,x.ActualEnd,x.AssignedToUserId,x.AssignedToName,x.RequiresProductionStop,x.DowntimeId,x.DowntimeMinutes,x.LaborMinutes,x.FailureCause,x.WorkPerformed,x.Resolution,x.VerificationNotes,x.VerifiedAt,x.TotalPartsCost,x.TotalLaborCost,x.TotalExternalServiceCost,x.TotalMaintenanceCost,x.Currency,x.IsClosed,x.ClosedAt}).FirstOrDefaultAsync(ct);return x is null?NotFound(ApiResponse<object>.Fail("Bakım iş emri bulunamadı.")):Ok(ApiResponse<object>.SuccessResponse(x));}
 [HttpPost,Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceWorkOrders),Idempotent]public async Task<IActionResult>Create(WorkOrderInput r,CancellationToken ct){if(!await db.MaintenanceAssets.AnyAsync(x=>x.Id==r.MaintenanceAssetId&&x.IsActive,ct))return NotFound(ApiResponse<object>.Fail("Bakım varlığı bulunamadı."));var x=new MaintenanceWorkOrder{Id=Guid.NewGuid(),MaintenanceWorkOrderNumber=await MaintenanceSupport.Next(db,"MWO",DateTime.UtcNow,ct),MaintenanceAssetId=r.MaintenanceAssetId,WorkType=r.WorkType,Priority=r.Priority,Title=r.Title,Description=r.Description,PlannedStart=r.PlannedStart.ToUniversalTime(),PlannedEnd=r.PlannedEnd?.ToUniversalTime(),RequiresProductionStop=r.RequiresProductionStop};db.Add(x);await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.MaintenanceWorkOrderNumber,x.Status}));}
 [HttpPut("{id:guid}"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceWorkOrders)]public async Task<IActionResult>Update(Guid id,WorkOrderInput r,CancellationToken ct){var x=await db.MaintenanceWorkOrders.FindAsync([id],ct);if(x is null)return NotFound();if(x.Status is "Completed" or "Verified" or "Closed" or "Cancelled")return Conflict(ApiResponse<object>.Fail("Tamamlanmış bakım iş emri değiştirilemez."));x.Priority=r.Priority;x.Title=r.Title;x.Description=r.Description;x.PlannedStart=r.PlannedStart;x.PlannedEnd=r.PlannedEnd;x.RequiresProductionStop=r.RequiresProductionStop;await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));}
 [HttpPost("{id:guid}/plan"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceWorkOrders),Idempotent]public Task<IActionResult>Plan(Guid id,CancellationToken ct)=>Set(id,"Planned",ct);[HttpPost("{id:guid}/assign"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceWorkOrders),Idempotent]public async Task<IActionResult>Assign(Guid id,AssignMaintenance r,CancellationToken ct){var x=await db.MaintenanceWorkOrders.FindAsync([id],ct);if(x is null)return NotFound();x.AssignedToUserId=r.UserId;x.AssignedToName=r.Name;x.Status="Assigned";await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));}
 [HttpPost("{id:guid}/start"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceWorkOrders),Idempotent]public async Task<IActionResult>Start(Guid id,CancellationToken ct){var x=await db.MaintenanceWorkOrders.FindAsync([id],ct);if(x is null)return NotFound(ApiResponse<object>.Fail("Bakım iş emri bulunamadı."));if(x.Status=="InProgress")return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status},"Bu bakım iş emri daha önce başlatılmış."));if(x.Status is not("Assigned" or "Planned" or "WaitingForPart" or "WaitingForProduction"))return Conflict(ApiResponse<object>.Fail("Bakım iş emri bu durumda başlatılamaz."));x.Status="InProgress";x.ActualStart??=DateTime.UtcNow;await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status,x.ActualStart}));}
 [HttpPost("{id:guid}/wait-for-part"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceWorkOrders),Idempotent]public Task<IActionResult>Wait(Guid id,CancellationToken ct)=>Set(id,"WaitingForPart",ct);[HttpPost("{id:guid}/resume"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceWorkOrders),Idempotent]public Task<IActionResult>Resume(Guid id,CancellationToken ct)=>Set(id,"InProgress",ct);
 [HttpPost("{id:guid}/complete"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceWorkOrders),Idempotent]public async Task<IActionResult>Complete(Guid id,CompleteMaintenance r,CancellationToken ct){var x=await db.MaintenanceWorkOrders.FindAsync([id],ct);if(x is null)return NotFound(ApiResponse<object>.Fail("Bakım iş emri bulunamadı."));if(x.Status=="Completed")return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));if(x.Status!="InProgress")return Conflict(ApiResponse<object>.Fail("Bakım iş emri devam etmiyor."));var missing=await db.MaintenanceChecklistResults.AnyAsync(z=>z.MaintenanceWorkOrderId==id&&z.TemplateItem.IsRequired&&!z.IsCompleted,ct);if(missing)return Conflict(ApiResponse<object>.Fail("Tamamlanması gereken kontrol listesi maddeleri bulunuyor."));if(await db.MaintenancePartUsages.AnyAsync(z=>z.MaintenanceWorkOrderId==id&&z.Status=="Draft",ct))return Conflict(ApiResponse<object>.Fail("Taslak bakım parçaları post edilmeli veya iptal edilmelidir."));x.ActualEnd=DateTime.UtcNow;x.Status="Completed";x.WorkPerformed=r.WorkPerformed;x.Resolution=r.Resolution;x.FailureCause=r.FailureCause;x.LaborMinutes=r.LaborMinutes;x.TotalLaborCost=r.TotalLaborCost;x.TotalExternalServiceCost=r.TotalExternalServiceCost;x.TotalPartsCost=await db.MaintenancePartUsages.Where(z=>z.MaintenanceWorkOrderId==id&&z.Status=="Posted").SumAsync(z=>z.TotalCost??0,ct);x.TotalMaintenanceCost=(x.TotalPartsCost??0)+(x.TotalLaborCost??0)+(x.TotalExternalServiceCost??0);x.Currency=r.Currency;if(x.MaintenanceRequestId.HasValue){var req=await db.MaintenanceRequests.FindAsync([x.MaintenanceRequestId.Value],ct);if(req is not null){req.Status="Resolved";req.ResolutionSummary=r.Resolution;}}if(x.DowntimeId.HasValue){var d=await db.ProductionDowntimes.FindAsync([x.DowntimeId.Value],ct);if(d is not null&&d.IsOpen){d.EndTime=x.ActualEnd;d.DurationMinutes=(decimal)(x.ActualEnd.Value-d.StartTime).TotalMinutes;d.IsOpen=false;x.DowntimeMinutes=d.DurationMinutes??0;}}await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status,x.TotalMaintenanceCost}));}
 [HttpPost("{id:guid}/verify"),Authorize(Policy=AuthorizationPolicies.CanVerifyMaintenance),Idempotent]public async Task<IActionResult>Verify(Guid id,ReasonInput r,CancellationToken ct){var x=await db.MaintenanceWorkOrders.FindAsync([id],ct);if(x is null)return NotFound();if(x.Status=="Verified")return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));if(x.Status!="Completed")return Conflict(ApiResponse<object>.Fail("Yalnız tamamlanmış bakım iş emri doğrulanabilir."));x.Status="Verified";x.VerificationNotes=r.Reason;x.VerifiedAt=DateTime.UtcNow;x.VerifiedByUserId=user.UserId;await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));}
 [HttpPost("{id:guid}/close"),Authorize(Policy=AuthorizationPolicies.CanVerifyMaintenance),Idempotent]public async Task<IActionResult>Close(Guid id,CancellationToken ct){var x=await db.MaintenanceWorkOrders.FindAsync([id],ct);if(x is null)return NotFound();if(x.Status=="Closed")return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));if(x.Status!="Verified")return Conflict(ApiResponse<object>.Fail("Doğrulanmamış bakım iş emri kapatılamaz."));x.Status="Closed";x.IsClosed=true;x.ClosedAt=DateTime.UtcNow;x.ClosedBy=user.UserId;if(x.MaintenanceRequestId.HasValue){var req=await db.MaintenanceRequests.FindAsync([x.MaintenanceRequestId.Value],ct);if(req is not null)req.Status="Closed";}await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));}
 [HttpPost("{id:guid}/cancel"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceWorkOrders),Idempotent]public async Task<IActionResult>Cancel(Guid id,ReasonInput r,CancellationToken ct){if(string.IsNullOrWhiteSpace(r.Reason))return BadRequest(ApiResponse<object>.Fail("İptal gerekçesi zorunludur."));if(await db.MaintenancePartUsages.AnyAsync(x=>x.MaintenanceWorkOrderId==id&&x.Status=="Posted",ct))return Conflict(ApiResponse<object>.Fail("Post edilmiş bakım parçaları önce geri alınmalıdır."));return await Set(id,"Cancelled",ct);}
 [HttpGet("{id:guid}/timeline")]public async Task<IActionResult>Timeline(Guid id,CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.AuditLogs.AsNoTracking().Where(x=>x.EntityId==id.ToString()).OrderBy(x=>x.Timestamp).Select(x=>new{x.Timestamp,x.Action,x.EntityName,x.UserName,x.AffectedColumns}).ToListAsync(ct)));[HttpGet("summary")]public async Task<IActionResult>Summary(CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(new{InProgress=await db.MaintenanceWorkOrders.CountAsync(x=>x.Status=="InProgress",ct),WaitingForPart=await db.MaintenanceWorkOrders.CountAsync(x=>x.Status=="WaitingForPart",ct),Completed=await db.MaintenanceWorkOrders.CountAsync(x=>x.Status=="Completed",ct)}));
 async Task<IActionResult>Set(Guid id,string status,CancellationToken ct){var x=await db.MaintenanceWorkOrders.FindAsync([id],ct);if(x is null)return NotFound(ApiResponse<object>.Fail("Bakım iş emri bulunamadı."));if(x.Status is "Closed" or "Cancelled")return Conflict(ApiResponse<object>.Fail("Terminal bakım iş emri değiştirilemez."));x.Status=status;await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));}
}

[ApiController,ApiVersion("1.0"),Route("api/v{version:apiVersion}/preventive-maintenance-plans"),Authorize(Policy=AuthorizationPolicies.CanViewMaintenance)]
public class PreventiveMaintenancePlansController(ApplicationDbContext db):ControllerBase
{
 [HttpGet]public async Task<IActionResult>List(CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.PreventiveMaintenancePlans.AsNoTracking().OrderBy(x=>x.NextDueDate).Select(x=>new{x.Id,x.PlanCode,x.MaintenanceAssetId,Asset=x.MaintenanceAsset.AssetName,x.Name,x.FrequencyType,x.FrequencyValue,x.LastCompletedDate,x.NextDueDate,x.EstimatedDurationMinutes,x.RequiresProductionStop,x.DefaultPriority,x.AssignedToUserId,x.IsActive,x.AutoCreateWorkOrder,x.AdvanceCreateDays}).ToListAsync(ct)));[HttpGet("{id:guid}")]public async Task<IActionResult>Get(Guid id,CancellationToken ct){var x=await db.PreventiveMaintenancePlans.AsNoTracking().FirstOrDefaultAsync(x=>x.Id==id,ct);return x is null?NotFound():Ok(ApiResponse<object>.SuccessResponse(x));}
 [HttpPost,Authorize(Policy=AuthorizationPolicies.CanManagePreventiveMaintenance),Idempotent]public async Task<IActionResult>Create(PlanInput r,CancellationToken ct){if(r.FrequencyValue<=0)return BadRequest(ApiResponse<object>.Fail("Bakım sıklığı sıfırdan büyük olmalıdır."));var x=new PreventiveMaintenancePlan{Id=Guid.NewGuid(),PlanCode=r.PlanCode,MaintenanceAssetId=r.MaintenanceAssetId,Name=r.Name,Description=r.Description,FrequencyType=r.FrequencyType,FrequencyValue=r.FrequencyValue,StartDate=r.StartDate.Date,NextDueDate=MaintenanceSupport.NextDue(r.StartDate.Date,r.FrequencyType,r.FrequencyValue),EstimatedDurationMinutes=r.EstimatedDurationMinutes,RequiresProductionStop=r.RequiresProductionStop,DefaultPriority=r.DefaultPriority,ChecklistTemplateId=r.ChecklistTemplateId,AutoCreateWorkOrder=r.AutoCreateWorkOrder,AdvanceCreateDays=r.AdvanceCreateDays,Notes=r.Notes};db.Add(x);await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.PlanCode,x.NextDueDate}));}
 [HttpPut("{id:guid}"),Authorize(Policy=AuthorizationPolicies.CanManagePreventiveMaintenance)]public async Task<IActionResult>Update(Guid id,PlanInput r,CancellationToken ct){var x=await db.PreventiveMaintenancePlans.FindAsync([id],ct);if(x is null)return NotFound();x.Name=r.Name;x.Description=r.Description;x.FrequencyType=r.FrequencyType;x.FrequencyValue=r.FrequencyValue;x.EstimatedDurationMinutes=r.EstimatedDurationMinutes;x.RequiresProductionStop=r.RequiresProductionStop;x.DefaultPriority=r.DefaultPriority;x.ChecklistTemplateId=r.ChecklistTemplateId;x.AutoCreateWorkOrder=r.AutoCreateWorkOrder;x.AdvanceCreateDays=r.AdvanceCreateDays;x.Notes=r.Notes;await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.NextDueDate}));}
 [HttpPost("{id:guid}/activate"),Authorize(Policy=AuthorizationPolicies.CanManagePreventiveMaintenance)]public Task<IActionResult>Activate(Guid id,CancellationToken ct)=>Toggle(id,true,ct);[HttpPost("{id:guid}/deactivate"),Authorize(Policy=AuthorizationPolicies.CanManagePreventiveMaintenance)]public Task<IActionResult>Deactivate(Guid id,CancellationToken ct)=>Toggle(id,false,ct);
 [HttpGet("due-preview")]public async Task<IActionResult>Preview(DateTime? dueDate,CancellationToken ct){var d=(dueDate??DateTime.UtcNow.Date).Date;return Ok(ApiResponse<object>.SuccessResponse(await db.PreventiveMaintenancePlans.AsNoTracking().Where(x=>x.IsActive&&x.AutoCreateWorkOrder&&x.NextDueDate<=d.AddDays(x.AdvanceCreateDays)).Select(x=>new{x.Id,x.PlanCode,x.Name,x.NextDueDate,Asset=x.MaintenanceAsset.AssetName,Warning=x.FrequencyType=="OperatingHours"||x.FrequencyType=="ProductionCycles"?"Sayaç verisi olmadan otomatik üretilemez.":null}).ToListAsync(ct)));}
 [HttpPost("generate-due"),Authorize(Policy=AuthorizationPolicies.CanManagePreventiveMaintenance),Idempotent]public async Task<IActionResult>Generate(GenerateDue r,CancellationToken ct){var date=(r.DueDate??DateTime.UtcNow.Date).Date;var plans=await db.PreventiveMaintenancePlans.Where(x=>x.IsActive&&x.AutoCreateWorkOrder&&x.NextDueDate<=date.AddDays(x.AdvanceCreateDays)&&x.FrequencyType!="OperatingHours"&&x.FrequencyType!="ProductionCycles"&&x.FrequencyType!="Manual").ToListAsync(ct);var made=0;foreach(var p in plans){var due=p.NextDueDate;if(await db.MaintenanceWorkOrders.AnyAsync(x=>x.PreventiveMaintenancePlanId==p.Id&&x.PlannedStart.Date==due.Date&&x.Status!="Cancelled",ct))continue;db.MaintenanceWorkOrders.Add(new MaintenanceWorkOrder{Id=Guid.NewGuid(),MaintenanceWorkOrderNumber=await MaintenanceSupport.Next(db,"MWO",DateTime.UtcNow,ct),MaintenanceAssetId=p.MaintenanceAssetId,PreventiveMaintenancePlanId=p.Id,WorkType="Preventive",Priority=p.DefaultPriority,Title=p.Name,Description=p.Description??p.Name,Status="Planned",PlannedStart=due,PlannedEnd=due.AddMinutes(p.EstimatedDurationMinutes),AssignedToUserId=p.AssignedToUserId,RequiresProductionStop=p.RequiresProductionStop});p.LastGeneratedDate=DateTime.UtcNow;p.NextDueDate=MaintenanceSupport.NextDue(due,p.FrequencyType,p.FrequencyValue);made++;await db.SaveChangesAsync(ct);}return Ok(ApiResponse<object>.SuccessResponse(new{Created=made,Evaluated=plans.Count}));}
 [HttpGet("calendar")]public Task<IActionResult>Calendar(CancellationToken ct)=>List(ct);[HttpGet("summary")]public async Task<IActionResult>Summary(CancellationToken ct){var d=DateTime.UtcNow.Date;return Ok(ApiResponse<object>.SuccessResponse(new{Active=await db.PreventiveMaintenancePlans.CountAsync(x=>x.IsActive,ct),Overdue=await db.PreventiveMaintenancePlans.CountAsync(x=>x.IsActive&&x.NextDueDate<d,ct),DueIn7Days=await db.PreventiveMaintenancePlans.CountAsync(x=>x.IsActive&&x.NextDueDate>=d&&x.NextDueDate<=d.AddDays(7),ct),DueIn30Days=await db.PreventiveMaintenancePlans.CountAsync(x=>x.IsActive&&x.NextDueDate>=d&&x.NextDueDate<=d.AddDays(30),ct)}));}async Task<IActionResult>Toggle(Guid id,bool active,CancellationToken ct){var x=await db.PreventiveMaintenancePlans.FindAsync([id],ct);if(x is null)return NotFound();x.IsActive=active;await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.IsActive}));}
}

public record WorkOrderInput(Guid MaintenanceAssetId,string WorkType,string Priority,string Title,string Description,DateTime PlannedStart,DateTime? PlannedEnd,bool RequiresProductionStop);public record CompleteMaintenance(string WorkPerformed,string Resolution,string? FailureCause,decimal LaborMinutes,decimal? TotalLaborCost,decimal? TotalExternalServiceCost,string Currency);public record PlanInput(string PlanCode,Guid MaintenanceAssetId,string Name,string? Description,string FrequencyType,int FrequencyValue,DateTime StartDate,int EstimatedDurationMinutes,bool RequiresProductionStop,string DefaultPriority,Guid? ChecklistTemplateId,bool AutoCreateWorkOrder,int AdvanceCreateDays,string? Notes);public record GenerateDue(DateTime? DueDate);
